declare @sql nvarchar(max);
declare @params nvarchar(max);
declare @server_status varchar(50);
declare @is_decommissioned bit;
declare @host varchar(255);
declare @server varchar(125);

set @server = case when '$server_input' <> '' then '$server_input' else null end;
set @host = case when '$host_input' <> '' then '$host_input' else null end;
set @server_status = '$server_status';
set @is_decommissioned = case when @server_status = 'Online' then 0
                              when @server_status = 'Offline' then 1
                              when @server_status = 'All' then null
                              else null
                              end

set @params = N'@is_decommissioned bit, @host varchar(255), @server varchar(255)';

set quoted_identifier off;
set @sql = "
/* $__dashboard */
select [server], [server_port], [domain], [friendly_name], [stability], [priority], [server_type], [has_hadr], [hadr_strategy], [backup_strategy], [server_owner_email], [rdp_credential], [sql_credential], [is_monitoring_enabled], [is_maintenance_scheduled], [is_tde_implemented], [enabled_restart_schedule], [is_decommissioned], [more_info], [created_date_utc], [is_onboarded]
from dbo.sma_servers s
where 1=1
"+(case when @server_status = 'All' then '--' else '' end)+"and s.is_decommissioned = @is_decommissioned
"+(case when @server is not null then '' else '--' end)+"and s.server = @server
";
set quoted_identifier off;

exec dbo.sp_executesql @sql, @params, @is_decommissioned, @host, @server;

