declare @warning_threshold_days int;
declare @critical_threshold_days int;
declare @sql nvarchar(max)
declare @params nvarchar(max)
declare @sql_instance varchar(125)
declare @login_name varchar(125)

set @warning_threshold_days = $login_expiry_warning_threshold_days;
set @critical_threshold_days = $login_expiry_critical_threshold_days;
set @sql_instance = case when '$server_input' = '' then null else '$server_input' end
set @login_name = case when '$login_input' = '' then null else '$login_input' end

set @params = N'@warning_threshold_days int, @critical_threshold_days int, @sql_instance varchar(125), @login_name varchar(125)';

set @sql = 'select	[collection_time] = DATEADD(mi, DATEDIFF(mi, getdate(), getutcdate()), collection_time), 
                    [sql_instance], [login_name], [is_sysadmin], 
                    [password_last_set_time] = DATEADD(mi, DATEDIFF(mi, getdate(), getutcdate()), password_last_set_time), 
                    [password_expiration], [is_expired], [is_locked], [days_until_expiration], [login_owner_group_email], [server_owner_email], [app_team_emails], [application_owner_emails]
from dbo.all_server_login_expiry_info_dashboard lei
where 1=1
and lei.days_until_expiration <= @warning_threshold_days
and left(lower(login_name),6) <> ''bidba.''
'+(case when @sql_instance is null then '--' else '' end)+'and sql_instance = @sql_instance
'+(case when @login_name is null then '--' else '' end)+'and login_name = @login_name
';

exec dbo.sp_executesql @sql, @params, @warning_threshold_days, @critical_threshold_days, @sql_instance, @login_name;

declare @sql nvarchar(max);
declare @params nvarchar(max);
declare @server_status varchar(50);
declare @is_decommissioned bit;
declare @email varchar(255);
declare @login varchar(125);
declare @host varchar(255);
declare @server varchar(125);

set @server = case when '$server_input' <> '' then '$server_input' else null end;
set @host = case when '$host_input' <> '' then '$host_input' else null end;
set @email = case when '$email' <> '' then '$email' else null end;
set @login = case when '$login_input' <> '' then '$login_input' else null end;

set @server_status = '$server_status';
set @is_decommissioned = case when @server_status = 'Online' then 0
                              when @server_status = 'Offline' then 1
                              when @server_status = 'All' then null
                              else null
                              end

set @params = N'@is_decommissioned bit, @host varchar(255), @server varchar(255), @email varchar(255), @login varchar(125)';

set quoted_identifier off;
set @sql = "
/* $__dashboard */
select [server] = coalesce(s.[server],lem.[sql_instance_ip]), s.server_port, lem.[login_name], lem.[owner_group_email], 
      lem.[sql_instance_name], lem.[server_alias_name], 
      lem.[at_server_name], lem.[host_name], lem.[created_date], 
      lem.[created_by], lem.[is_deleted], lem.[remarks]
from dbo.login_email_mapping lem
left join dbo.sma_servers s
	on s.server = lem.[sql_instance_ip]
"+(case when @server_status = 'All' then '--' else '' end)+" and s.is_decommissioned = @is_decommissioned
"+(case when @server_status = 'All' then '--' else '' end)+" and lem.is_deleted = @is_decommissioned
where 1=1
"+(case when @server is not null then '' else '--' end)+"and s.server = @server
"+(case when @email is not null then '' else '--' end)+"and lem.[owner_group_email] = @email
"+(case when @login is not null then '' else '--' end)+"and lem.[login_name] = @login
";
set quoted_identifier off;

exec dbo.sp_executesql @sql, @params, @is_decommissioned, @host, @server, @email, @login;

